#include <SD.h>
#define P_PIN A0
#define VALVE_RELAY 6
#define BUZZER 8
#define LED 9
#define SD_CS 10
#define VREF 5.0f
#define P_SURGE_LIMIT 200.0f
#define P_BURST_DROP 100.0f
#define DT 1.0f
float intg=0,lastE=0;
float closeTime=10.0f;
float prevP=350.0f;

float joukowsky_surge_pressure(float rho,float a,float dv){
  return rho*a*fabs(dv)/1000.0f;
}

float read_pressure_kPa(){
  float V=(analogRead(P_PIN)/1023.0f)*VREF;
  return ((V/VREF)-0.04f)*700.0f/0.9f;
}

float sample_peak_surge(int n){
  float base=read_pressure_kPa(),pk=base;
  for(int i=0;i<n;i++){float p=read_pressure_kPa();if(p>pk)pk=p;delayMicroseconds(1000);}
  return pk-base;
}

void adjust_close_time(float surge){
  float e=surge-P_SURGE_LIMIT;
  intg+=e*DT; intg=constrain(intg,-30,30);
  float d=(e-lastE)/DT; lastE=e;
  closeTime+=0.4f*e/P_SURGE_LIMIT*10.0f;
  closeTime=constrain(closeTime,5.0f,60.0f);
}

void slow_close_valve(){
  digitalWrite(VALVE_RELAY,HIGH);
  delay((unsigned long)(closeTime*1000));
  digitalWrite(VALVE_RELAY,LOW);
}

void run_alarm(float surge,float P){
  if(surge>P_SURGE_LIMIT||prevP-P>P_BURST_DROP){tone(BUZZER,2000);analogWrite(LED,255);}
  else{noTone(BUZZER);analogWrite(LED,0);}
}

void log_sd(float P,float surge){
  File f=SD.open("hammer.csv",FILE_WRITE);
  if(f){f.print(millis());f.print(',');f.print(P);f.print(',');f.println(surge);f.close();}
}

void setup(){Serial.begin(115200);SD.begin(SD_CS);pinMode(VALVE_RELAY,OUTPUT);pinMode(BUZZER,OUTPUT);pinMode(LED,OUTPUT);}

void loop(){
  float P=read_pressure_kPa();
  float surge=sample_peak_surge(100);
  adjust_close_time(surge);
  run_alarm(surge,P);
  log_sd(P,surge);
  prevP=P;
  Serial.print("P=");Serial.print(P);Serial.print(" dP=");Serial.println(surge);
  delay(100);
}
